#nullable enable // autogenerated

using MVZ2.Vanilla;
using PVZEngine;

namespace MVZ2.GameContent.Maps
{
    public static class VanillaMapElementNames
    {
        public const string dreamKey = "dream_key";
        public const string nightmareBox = "nightmare_box";
    }
    public static class VanillaMapElementID
    {
        public static readonly NamespaceID dreamKey = Get(VanillaMapElementNames.dreamKey);
        public static readonly NamespaceID nightmareBox = Get(VanillaMapElementNames.nightmareBox);
        private static NamespaceID Get(string name)
        {
            return new NamespaceID(VanillaMod.spaceName, name);
        }
    }
}
